function validateItems(items) {
  if (!Array.isArray(items)) return false;

  for (const item of items) {
    if (
      !item.name ||
      typeof item.name !== "string" ||
      typeof item.qty !== "number" ||
      item.qty <= 0
    ) {
      return false;
    }
  }

  return true;
}

module.exports = { validateItems };
